SELECT VenditeEPrenotazioniUnioneStatus.*, Customer.[Fast Shipment] AS [Customer_Fast Shipment], [Sales Header].[Ship-to City] AS CittaSpedizione, [Sales Line].[Customer Order Ref_], [Sales Line].Reference, [Sales Header].[Salesperson Code] AS SalespersonCode, Salesperson_Purchaser.Name AS SalesPersonName, [Sales Line].[Constant Variable Code] AS Colore, [Sales Line].[Assortment Code] AS Assortimento, [Sales Line].No_, Item.Description, Item.[Description 2], Item.[Trademark Code], Item.[Collection Code], Item.[Line Code], Customer.[Reservation Priority], Customer.[Current Risk], [Sales Header].[Sell-to Customer No_] AS CustomerNo, Customer.Name AS CustomerName, [Sales Line].[Requested Delivery Date], DateDiff("d",[Sales Line.requested delivery date],[date reservation]) AS giorniRitardo, Customer.[Geographical Zone] AS [Geographical Zone1], [Geographical Zone].Description AS GeographicalZone1Description, Customer.[Geographical Zone 2], [Geographical Zone_1].Description AS GeographicalZone2Description, [Sales Header].[Payment Method Code], [Sales Header].[Payment Terms Code], Customer.[Blocked For Assignments], Vendor.No_ AS VendorByItem, Vendor.Name AS VendorNameByItem, [Sales Header].[Securities Received], [Sales Header].[Fast Shipping], Item.[Advertising Material], Item.Manufacturer, Vendor_1.Name AS ManufacturerName
FROM ((((((((VenditeEPrenotazioniUnioneStatus LEFT JOIN [Sales Line] ON (VenditeEPrenotazioniUnioneStatus.ordineNumero = [Sales Line].[Document No_]) AND (VenditeEPrenotazioniUnioneStatus.OrdineRiga = [Sales Line].[Line No_])) LEFT JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) LEFT JOIN Item ON [Sales Line].No_ = Item.No_) LEFT JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].[Code]) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].[Code]) LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_;

